+import winston from 'winston';
+import chalk from 'chalk';
+
+const customFormat = winston.format.printf(({ level, message, timestamp }) => {
+  const colorMap: Record<string, (text: string) => string> = {
+    error: chalk.red,
+    warn: chalk.yellow,
+    info: chalk.blue,
+    debug: chalk.gray,
+  };
+  
+  const colorFn = colorMap[level] || chalk.white;
+  return `${chalk.gray(timestamp)} ${colorFn(level.toUpperCase())}: ${message}`;
+});
+
+export const logger = winston.createLogger({
+  level: process.env.LOG_LEVEL || 'info',
+  format: winston.format.combine(
+    winston.format.timestamp({ format: 'YYYY-MM-DD HH:mm:ss' }),
+    winston.format.errors({ stack: true }),
+    customFormat
+  ),
+  transports: [
+    new winston.transports.Console(),
+    new winston.transports.File({ 
+      filename: 'bcb-error.log', 
+      level: 'error',
+      format: winston.format.combine(
+        winston.format.timestamp(),
+        winston.format.json()
+      )
+    }),
+    new winston.transports.File({ 
+      filename: 'bcb-combined.log',
+      format: winston.format.combine(
+        winston.format.timestamp(),
+        winston.format.json()
+      )
+    })
+  ]
+});
+
+export class ConsoleReporter {
+  static success(message: string): void {
+    console.log(chalk.green('✓'), message);
+  }
+
+  static error(message: string): void {
+    console.log(chalk.red('✗'), message);
+  }
+
+  static warning(message: string): void {
+    console.log(chalk.yellow('⚠'), message);
+  }
+
+  static info(message: string): void {
+    console.log(chalk.blue('ℹ'), message);
+  }
+
+  static section(title: string): void {
+    console.log('\n' + chalk.bold.cyan(`━━━ ${title} ━━━`) + '\n');
+  }
+
+  static subsection(title: string): void {
+    console.log(chalk.bold(title));
+  }
+
+  static list(items: string[]): void {
+    items.forEach(item => console.log(chalk.gray('  •'), item));
+  }
+
+  static keyValue(key: string, value: string | number): void {
+    console.log(chalk.gray(`  ${key}:`), chalk.white(value));
+  }
+
+  static progress(current: number, total: number, message: string): void {
+    const percentage = Math.round((current / total) * 100);
+    const bar = '█'.repeat(Math.floor(percentage / 2)) + '░'.repeat(50 - Math.floor(percentage / 2));
+    process.stdout.write(`\r${chalk.cyan(bar)} ${percentage}% ${message}`);
+    if (current === total) {
+      process.stdout.write('\n');
+    }
+  }
+}
+
