+import { Finding, FindingCategory, Severity, FixStrategy, AnalysisContext } from '../types';
+import fs from 'fs-extra';
+import { execSync } from 'child_process';
+import path from 'path';
+
+export class SecurityAnalyzer {
+  async analyze(context: AnalysisContext): Promise<Finding[]> {
+    const findings: Finding[] = [];
+
+    if (!context.config.rules['security-vulnerabilities']?.enabled) {
+      return findings;
+    }
+
+    // Check for hardcoded secrets
+    findings.push(...await this.checkHardcodedSecrets(context));
+
+    // Check npm audit if package.json exists
+    findings.push(...await this.checkNpmAudit(context));
+
+    // Check for insecure dependencies
+    findings.push(...await this.checkInsecureDependencies(context));
+
+    return findings;
+  }
+
+  private async checkHardcodedSecrets(context: AnalysisContext): Promise<Finding[]> {
+    const findings: Finding[] = [];
+
+    if (!context.file || !context.content) {
+      return findings;
+    }
+
+    const secretPatterns = [
+      { pattern: /(?:api[_-]?key|apikey)\s*[:=]\s*['"]([^'"]+)['"]/gi, name: 'API Key' },
+      { pattern: /(?:secret[_-]?key|secretkey)\s*[:=]\s*['"]([^'"]+)['"]/gi, name: 'Secret Key' },
+      { pattern: /(?:password|passwd|pwd)\s*[:=]\s*['"]([^'"]+)['"]/gi, name: 'Password' },
+      { pattern: /(?:token|auth[_-]?token)\s*[:=]\s*['"]([^'"]+)['"]/gi, name: 'Auth Token' },
+      { pattern: /(?:private[_-]?key|privatekey)\s*[:=]\s*['"]([^'"]+)['"]/gi, name: 'Private Key' },
+      { pattern: /(?:aws[_-]?access[_-]?key[_-]?id)\s*[:=]\s*['"]([^'"]+)['"]/gi, name: 'AWS Access Key' },
+      { pattern: /(?:aws[_-]?secret[_-]?access[_-]?key)\s*[:=]\s*['"]([^'"]+)['"]/gi, name: 'AWS Secret Key' },
+    ];
+
+    const lines = context.content.split('\n');
+
+    for (let i = 0; i < lines.length; i++) {
+      const line = lines[i];
+
+      for (const { pattern, name } of secretPatterns) {
+        const matches = line.matchAll(pattern);
+        for (const match of matches) {
+          // Skip if it's a placeholder or example
+          const value = match[1];
+          if (this.isPlaceholder(value)) {
+            continue;
+          }
+
+          findings.push({
+            id: this.generateId(),
+            category: FindingCategory.SECURITY,
+            severity: Severity.CRITICAL,
+            title: `Hardcoded ${name} detected`,
+            description: `Found a hardcoded ${name} in the source code. This is a security risk.`,
+            file: context.file.path,
+            line: i + 1,
+            code: line.trim(),
+            suggestion: 'Move sensitive data to environment variables or a secure configuration management system.',
+            fixStrategy: FixStrategy.MANUAL,
+            autoFixable: false,
+            metadata: {
+              secretType: name,
+            },
+          });
+        }
+      }
+    }
+
+    return findings;
+  }
+
+  private async checkNpmAudit(context: AnalysisContext): Promise<Finding[]> {
+    const findings: Finding[] = [];
+
+    const packageJsonPath = path.join(context.manifest.rootPath, 'package.json');
+    if (!(await fs.pathExists(packageJsonPath))) {
+      return findings;
+    }
+
+    try {
+      // Run npm audit
+      const result = execSync('npm audit --json', {
+        cwd: context.manifest.rootPath,
+        encoding: 'utf-8',
+        stdio: ['pipe', 'pipe', 'ignore'],
+      });
+
+      const auditData = JSON.parse(result);
+
+      if (auditData.vulnerabilities) {
+        for (const [pkgName, vulnData] of Object.entries(auditData.vulnerabilities)) {
+          const vuln = vulnData as any;
+          
+          findings.push({
+            id: this.generateId(),
+            category: FindingCategory.SECURITY,
+            severity: this.mapAuditSeverity(vuln.severity),
+            title: `Security vulnerability in ${pkgName}`,
+            description: vuln.via?.[0]?.title || `Vulnerability found in dependency ${pkgName}`,
+            file: packageJsonPath,
+            suggestion: `Update ${pkgName} to version ${vuln.fixAvailable?.version || 'latest'} or higher.`,
+            fixStrategy: FixStrategy.AUTOMATED,
+            autoFixable: true,
+            metadata: {
+              package: pkgName,
+              currentVersion: vuln.range,
+              fixVersion: vuln.fixAvailable?.version,
+              cve: vuln.via?.[0]?.cve,
+            },
+          });
+        }
+      }
+    } catch (error) {
+      // npm audit might fail if no package-lock.json exists
+      // This is not critical, so we just skip
+    }
+
+    return findings;
+  }
+
+  private async checkInsecureDependencies(context: AnalysisContext): Promise<Finding[]> {
+    const findings: Finding[] = [];
+
+    if (!context.manifest.dependencies) {
+      return findings;
+    }
+
+    const insecurePackages = [
+      'request', // Deprecated
+      'node-uuid', // Deprecated, use uuid
+      'colors', // Had malicious code
+      'faker', // Deprecated, use @faker-js/faker
+    ];
+
+    for (const pkg of insecurePackages) {
+      if (context.manifest.dependencies[pkg] || context.manifest.devDependencies?.[pkg]) {
+        findings.push({
+          id: this.generateId(),
+          category: FindingCategory.SECURITY,
+          severity: Severity.MEDIUM,
+          title: `Insecure or deprecated package: ${pkg}`,
+          description: `Package ${pkg} is deprecated or has known security issues.`,
+          file: path.join(context.manifest.rootPath, 'package.json'),
+          suggestion: this.getPackageReplacement(pkg),
+          fixStrategy: FixStrategy.MANUAL,
+          autoFixable: false,
+          metadata: {
+            package: pkg,
+          },
+        });
+      }
+    }
+
+    return findings;
+  }
+
+  private isPlaceholder(value: string): boolean {
+    const placeholders = [
+      'your-api-key',
+      'your-secret',
+      'your-password',
+      'your-token',
+      'xxx',
+      'yyy',
+      'zzz',
+      'example',
+      'test',
+      'demo',
+      'placeholder',
+      '***',
+      '...',
+    ];
+
+    const lowerValue = value.toLowerCase();
+    return placeholders.some(p => lowerValue.includes(p)) || value.length < 8;
+  }
+
+  private mapAuditSeverity(severity: string): Severity {
+    switch (severity.toLowerCase()) {
+      case 'critical':
+        return Severity.CRITICAL;
+      case 'high':
+        return Severity.HIGH;
+      case 'moderate':
+        return Severity.MEDIUM;
+      case 'low':
+        return Severity.LOW;
+      default:
+        return Severity.INFO;
+    }
+  }
+
+  private getPackageReplacement(pkg: string): string {
+    const replacements: Record<string, string> = {
+      'request': 'Use axios, node-fetch, or the native fetch API',
+      'node-uuid': 'Replace with uuid package',
+      'colors': 'Use chalk or picocolors instead',
+      'faker': 'Replace with @faker-js/faker',
+    };
+
+    return replacements[pkg] || 'Find a maintained alternative';
+  }
+
+  private generateId(): string {
+    return `sec-${Date.now()}-${Math.random().toString(36).substr(2, 9)}`;
+  }
+}
+
+// Made with Bob
