+import { Finding, RepairResult, FileChange, FixStrategy, BCBConfig } from '../types';
+import { AIProviderFactory } from '../ai/ai-provider';
+import { logger, ConsoleReporter } from '../utils/logger';
+import fs from 'fs-extra';
+import path from 'path';
+import simpleGit from 'simple-git';
+import inquirer from 'inquirer';
+
+export class RepairEngine {
+  private config: BCBConfig;
+  private aiProvider: any;
+
+  constructor(config: BCBConfig) {
+    this.config = config;
+    
+    if (config.ai.apiKey) {
+      this.aiProvider = AIProviderFactory.create(
+        config.ai.provider,
+        config.ai.apiKey,
+        config.ai.model
+      );
+    }
+  }
+
+  async repair(findings: Finding[], projectPath: string): Promise<RepairResult[]> {
+    ConsoleReporter.section('Repair Process');
+    
+    const results: RepairResult[] = [];
+    const autoFixableFindings = findings.filter(f => f.autoFixable);
+    const aiAssistedFindings = findings.filter(
+      f => !f.autoFixable && f.fixStrategy === FixStrategy.AI_ASSISTED
+    );
+
+    // Create backup if Git is available
+    const hasGit = await this.hasGitRepo(projectPath);
+    if (hasGit) {
+      ConsoleReporter.info('Creating Git checkpoint...');
+      await this.createGitCheckpoint(projectPath);
+    } else {
+      ConsoleReporter.warning('No Git repository found. Creating backup...');
+      await this.createBackup(projectPath);
+    }
+
+    // Auto-fix issues
+    if (autoFixableFindings.length > 0 && this.config.autoFix.enabled) {
+      ConsoleReporter.subsection(`Auto-fixing ${autoFixableFindings.length} issues`);
+      
+      for (const finding of autoFixableFindings) {
+        if (this.config.autoFix.requireApproval) {
+          const shouldFix = await this.promptForApproval(finding);
+          if (!shouldFix) {
+            continue;
+          }
+        }
+
+        const result = await this.applyAutomatedFix(finding);
+        results.push(result);
+        
+        if (result.success) {
+          ConsoleReporter.success(`Fixed: ${finding.title}`);
+        } else {
+          ConsoleReporter.error(`Failed: ${finding.title} - ${result.error}`);
+        }
+      }
+    }
+
+    // AI-assisted fixes
+    if (aiAssistedFindings.length > 0 && this.aiProvider) {
+      ConsoleReporter.subsection(`AI-assisted repairs for ${aiAssistedFindings.length} issues`);
+      
+      for (const finding of aiAssistedFindings) {
+        if (this.config.autoFix.requireApproval) {
+          const shouldFix = await this.promptForApproval(finding);
+          if (!shouldFix) {
+            continue;
+          }
+        }
+
+        const result = await this.applyAIAssistedFix(finding);
+        results.push(result);
+        
+        if (result.success) {
+          ConsoleReporter.success(`Fixed: ${finding.title}`);
+        } else {
+          ConsoleReporter.error(`Failed: ${finding.title} - ${result.error}`);
+        }
+      }
+    }
+
+    const successCount = results.filter(r => r.success).length;
+    ConsoleReporter.success(`Repair complete: ${successCount}/${results.length} fixes applied`);
+
+    return results;
+  }
+
+  private async applyAutomatedFix(finding: Finding): Promise<RepairResult> {
+    try {
+      const changes: FileChange[] = [];
+
+      if (!finding.file) {
+        return {
+          success: false,
+          findingId: finding.id,
+          strategy: FixStrategy.AUTOMATED,
+          changes: [],
+          error: 'No file specified',
+        };
+      }
+
+      const content = await fs.readFile(finding.file, 'utf-8');
+      let newContent = content;
+
+      // Apply specific fixes based on finding type
+      if (finding.title.includes('Console statement')) {
+        newContent = this.removeConsoleStatements(content, finding.line);
+      } else if (finding.title.includes('Debugger statement')) {
+        newContent = this.removeDebuggerStatements(content, finding.line);
+      } else if (finding.title.includes('naming convention')) {
+        // This would require more sophisticated AST manipulation
+        // For now, we'll skip it
+        return {
+          success: false,
+          findingId: finding.id,
+          strategy: FixStrategy.AUTOMATED,
+          changes: [],
+          error: 'Naming convention fixes require manual intervention',
+        };
+      }
+
+      if (newContent !== content) {
+        await fs.writeFile(finding.file, newContent, 'utf-8');
+        
+        changes.push({
+          file: finding.file,
+          type: 'modify',
+          originalContent: content,
+          newContent,
+        });
+
+        return {
+          success: true,
+          findingId: finding.id,
+          strategy: FixStrategy.AUTOMATED,
+          changes,
+        };
+      }
+
+      return {
+        success: false,
+        findingId: finding.id,
+        strategy: FixStrategy.AUTOMATED,
+        changes: [],
+        error: 'No changes needed',
+      };
+    } catch (error) {
+      return {
+        success: false,
+        findingId: finding.id,
+        strategy: FixStrategy.AUTOMATED,
+        changes: [],
+        error: String(error),
+      };
+    }
+  }
+
+  private async applyAIAssistedFix(finding: Finding): Promise<RepairResult> {
+    try {
+      if (!this.aiProvider) {
+        return {
+          success: false,
+          findingId: finding.id,
+          strategy: FixStrategy.AI_ASSISTED,
+          changes: [],
+          error: 'AI provider not configured',
+        };
+      }
+
+      if (!finding.file) {
+        return {
+          success: false,
+          findingId: finding.id,
+          strategy: FixStrategy.AI_ASSISTED,
+          changes: [],
+          error: 'No file specified',
+        };
+      }
+
+      const content = await fs.readFile(finding.file, 'utf-8');
+      
+      // Get AI suggestion
+      ConsoleReporter.info(`Getting AI suggestion for: ${finding.title}`);
+      const suggestion = await this.aiProvider.suggestFix(finding, content);
+      
+      // Extract code from AI response (simplified - would need better parsing)
+      const codeMatch = suggestion.match(/```[\w]*\n([\s\S]*?)\n```/);
+      if (!codeMatch) {
+        return {
+          success: false,
+          findingId: finding.id,
+          strategy: FixStrategy.AI_ASSISTED,
+          changes: [],
+          error: 'Could not extract code from AI response',
+          aiReasoning: suggestion,
+        };
+      }
+
+      const newContent = codeMatch[1];
+
+      // Show preview and ask for confirmation
+      if (this.config.autoFix.requireApproval) {
+        ConsoleReporter.subsection('AI Suggested Fix:');
+        console.log(suggestion);
+        
+        const { confirm } = await inquirer.prompt([
+          {
+            type: 'confirm',
+            name: 'confirm',
+            message: 'Apply this fix?',
+            default: false,
+          },
+        ]);
+
+        if (!confirm) {
+          return {
+            success: false,
+            findingId: finding.id,
+            strategy: FixStrategy.AI_ASSISTED,
+            changes: [],
+            error: 'User declined fix',
+            aiReasoning: suggestion,
+          };
+        }
+      }
+
+      await fs.writeFile(finding.file, newContent, 'utf-8');
+
+      return {
+        success: true,
+        findingId: finding.id,
+        strategy: FixStrategy.AI_ASSISTED,
+        changes: [
+          {
+            file: finding.file,
+            type: 'modify',
+            originalContent: content,
+            newContent,
+          },
+        ],
+        aiReasoning: suggestion,
+      };
+    } catch (error) {
+      return {
+        success: false,
+        findingId: finding.id,
+        strategy: FixStrategy.AI_ASSISTED,
+        changes: [],
+        error: String(error),
+      };
+    }
+  }
+
+  private removeConsoleStatements(content: string, line?: number): string {
+    const lines = content.split('\n');
+    
+    if (line !== undefined && line > 0 && line <= lines.length) {
+      // Remove specific line
+      lines[line - 1] = lines[line - 1].replace(/console\.\w+\([^)]*\);?/g, '');
+    } else {
+      // Remove all console statements
+      return content.replace(/console\.\w+\([^)]*\);?\n?/g, '');
+    }
+    
+    return lines.join('\n');
+  }
+
+  private removeDebuggerStatements(content: string, line?: number): string {
+    const lines = content.split('\n');
+    
+    if (line !== undefined && line > 0 && line <= lines.length) {
+      // Remove specific line
+      lines[line - 1] = lines[line - 1].replace(/debugger;?/g, '');
+    } else {
+      // Remove all debugger statements
+      return content.replace(/debugger;?\n?/g, '');
+    }
+    
+    return lines.join('\n');
+  }
+
+  private async hasGitRepo(projectPath: string): Promise<boolean> {
+    try {
+      const git = simpleGit(projectPath);
+      await git.status();
+      return true;
+    } catch {
+      return false;
+    }
+  }
+
+  private async createGitCheckpoint(projectPath: string): Promise<void> {
+    try {
+      const git = simpleGit(projectPath);
+      await git.add('.');
+      await git.commit('BCB: Checkpoint before automated repairs');
+      logger.info('Git checkpoint created');
+    } catch (error) {
+      logger.warn(`Failed to create Git checkpoint: ${error}`);
+    }
+  }
+
+  private async createBackup(projectPath: string): Promise<void> {
+    const backupPath = `${projectPath}.bcb-backup-${Date.now()}`;
+    await fs.copy(projectPath, backupPath);
+    logger.info(`Backup created at ${backupPath}`);
+  }
+
+  private async promptForApproval(finding: Finding): Promise<boolean> {
+    const { confirm } = await inquirer.prompt([
+      {
+        type: 'confirm',
+        name: 'confirm',
+        message: `Fix: ${finding.title} in ${path.basename(finding.file || '')}?`,
+        default: true,
+      },
+    ]);
+
+    return confirm;
+  }
+}
+
+// Made with Bob
