+import { AuditReport, Severity, FindingCategory } from '../types';
+import fs from 'fs-extra';
+import path from 'path';
+import { ConsoleReporter } from '../utils/logger';
+
+export class ReportGenerator {
+  async generate(report: AuditReport, format: string, outputPath?: string): Promise<void> {
+    switch (format) {
+      case 'json':
+        await this.generateJSON(report, outputPath);
+        break;
+      case 'html':
+        await this.generateHTML(report, outputPath);
+        break;
+      case 'markdown':
+        await this.generateMarkdown(report, outputPath);
+        break;
+      case 'terminal':
+      default:
+        this.generateTerminal(report);
+        break;
+    }
+  }
+
+  private async generateJSON(report: AuditReport, outputPath?: string): Promise<void> {
+    const json = JSON.stringify(report, null, 2);
+    
+    if (outputPath) {
+      await fs.writeFile(outputPath, json, 'utf-8');
+      ConsoleReporter.success(`JSON report saved to ${outputPath}`);
+    } else {
+      console.log(json);
+    }
+  }
+
+  private async generateMarkdown(report: AuditReport, outputPath?: string): Promise<void> {
+    const md = this.buildMarkdown(report);
+    
+    if (outputPath) {
+      await fs.writeFile(outputPath, md, 'utf-8');
+      ConsoleReporter.success(`Markdown report saved to ${outputPath}`);
+    } else {
+      console.log(md);
+    }
+  }
+
+  private async generateHTML(report: AuditReport, outputPath?: string): Promise<void> {
+    const html = this.buildHTML(report);
+    
+    if (outputPath) {
+      await fs.writeFile(outputPath, html, 'utf-8');
+      ConsoleReporter.success(`HTML report saved to ${outputPath}`);
+    } else {
+      console.log(html);
+    }
+  }
+
+  private generateTerminal(report: AuditReport): void {
+    ConsoleReporter.section('Audit Report');
+    
+    // Project info
+    ConsoleReporter.subsection('Project Information');
+    ConsoleReporter.keyValue('Path', report.projectPath);
+    ConsoleReporter.keyValue('Type', report.manifest.projectType);
+    ConsoleReporter.keyValue('Files', report.manifest.totalFiles);
+    ConsoleReporter.keyValue('Lines of Code', report.manifest.totalLines);
