+    
+    // Languages
+    if (Object.keys(report.manifest.languages).length > 0) {
+      console.log('\n  Languages:');
+      for (const [lang, lines] of Object.entries(report.manifest.languages)) {
+        const percentage = ((lines / report.manifest.totalLines) * 100).toFixed(1);
+        ConsoleReporter.keyValue(`    ${lang}`, `${lines} lines (${percentage}%)`);
+      }
+    }
+
+    // Summary
+    ConsoleReporter.subsection('Summary');
+    ConsoleReporter.keyValue('Total Findings', report.summary.totalFindings);
+    ConsoleReporter.keyValue('Auto-fixable', report.summary.autoFixableCount);
+    
+    console.log('\n  By Severity:');
+    for (const [severity, count] of Object.entries(report.summary.bySeverity)) {
+      if (count > 0) {
+        const icon = this.getSeverityIcon(severity as Severity);
+        ConsoleReporter.keyValue(`    ${icon} ${severity}`, count);
+      }
+    }
+
+    console.log('\n  By Category:');
+    for (const [category, count] of Object.entries(report.summary.byCategory)) {
