+        console.log(`\n  ${icon} ${finding.title}`);
+        ConsoleReporter.keyValue('    Location', location);
+        ConsoleReporter.keyValue('    Category', finding.category);
+        if (finding.autoFixable) {
+          ConsoleReporter.info('    ✨ Auto-fixable');
+        }
+      }
+    }
+  }
+
+  private buildMarkdown(report: AuditReport): string {
+    let md = `# BCB Audit Report\n\n`;
+    md += `**Generated:** ${report.timestamp.toISOString()}\n\n`;
+    
+    // Project Info
+    md += `## Project Information\n\n`;
+    md += `- **Path:** ${report.projectPath}\n`;
+    md += `- **Type:** ${report.manifest.projectType}\n`;
+    md += `- **Files:** ${report.manifest.totalFiles}\n`;
+    md += `- **Lines of Code:** ${report.manifest.totalLines}\n`;
+    md += `- **Score:** ${report.score}/100\n\n`;
+
+    // Languages
+    if (Object.keys(report.manifest.languages).length > 0) {
+      md += `### Languages\n\n`;
+      for (const [lang, lines] of Object.entries(report.manifest.languages)) {
+        const percentage = ((lines / report.manifest.totalLines) * 100).toFixed(1);
+        md += `- **${lang}:** ${lines} lines (${percentage}%)\n`;
+      }
+      md += `\n`;
+    }
+
+    // Summary
+    md += `## Summary\n\n`;
+    md += `- **Total Findings:** ${report.summary.totalFindings}\n`;
+    md += `- **Auto-fixable:** ${report.summary.autoFixableCount}\n\n`;
+
+    md += `### By Severity\n\n`;
+    for (const [severity, count] of Object.entries(report.summary.bySeverity)) {
+      if (count > 0) {
+        md += `- **${severity}:** ${count}\n`;
+      }
+    }
+
+    md += `\n### By Category\n\n`;
+    for (const [category, count] of Object.entries(report.summary.byCategory)) {
+      if (count > 0) {
+        md += `- **${category}:** ${count}\n`;
+      }
+    }
+
+    // Recommendations
+    if (report.recommendations.length > 0) {
+      md += `\n## Recommendations\n\n`;
+      for (const rec of report.recommendations) {
+        md += `- ${rec}\n`;
+      }
+    }
+
+    // Findings
+    if (report.findings.length > 0) {
+      md += `\n## Findings\n\n`;
+      
+      const bySeverity = this.groupBySeverity(report.findings);
+      
+      for (const severity of [Severity.CRITICAL, Severity.HIGH, Severity.MEDIUM, Severity.LOW, Severity.INFO]) {
+        const findings = bySeverity[severity];
+        if (findings && findings.length > 0) {
+          md += `### ${severity.toUpperCase()} (${findings.length})\n\n`;
+          
+          for (const finding of findings) {
+            md += `#### ${finding.title}\n\n`;
+            md += `- **Category:** ${finding.category}\n`;
+            md += `- **File:** ${finding.file || 'N/A'}\n`;
