+            md += `${finding.description}\n\n`;
+            if (finding.suggestion) {
+              md += `**Suggestion:** ${finding.suggestion}\n\n`;
+            }
+          }
+        }
+      }
+    }
+
+    return md;
+  }
+
+  private buildHTML(report: AuditReport): string {
