+        .severity-high { color: #fd7e14; }
+        .severity-medium { color: #ffc107; }
+        .severity-low { color: #28a745; }
+        .severity-info { color: #17a2b8; }
+        .finding { background: #f8f9fa; padding: 15px; margin: 10px 0; border-radius: 4px; border-left: 4px solid #ccc; }
+        .finding.critical { border-left-color: #dc3545; }
+        .finding.high { border-left-color: #fd7e14; }
+        .finding.medium { border-left-color: #ffc107; }
+        .finding.low { border-left-color: #28a745; }
+        .badge { display: inline-block; padding: 4px 8px; border-radius: 3px; font-size: 12px; font-weight: bold; }
+        .badge.auto-fix { background: #28a745; color: white; }
+        .recommendations { background: #e7f3ff; padding: 20px; border-radius: 4px; border-left: 4px solid #007bff; }
+        .recommendations ul { margin: 10px 0; }
+    </style>
+</head>
+<body>
+    <div class="container">
+        <h1>BCB Audit Report</h1>
+        <p><strong>Generated:</strong> ${report.timestamp.toISOString()}</p>
+        <p><strong>Project:</strong> ${report.projectPath}</p>
+        
+        <div style="text-align: center; margin: 30px 0;">
+            <div class="score">${report.score}/100</div>
+            <p>Overall Code Quality Score</p>
+        </div>
+
+        <div class="summary">
+            <div class="summary-card">
+                <h3>Total Findings</h3>
+                <div class="value">${report.summary.totalFindings}</div>
+            </div>
+            <div class="summary-card">
+                <h3>Auto-fixable</h3>
+                <div class="value">${report.summary.autoFixableCount}</div>
+            </div>
+            <div class="summary-card">
+                <h3>Files Analyzed</h3>
+                <div class="value">${report.manifest.totalFiles}</div>
+            </div>
+            <div class="summary-card">
+                <h3>Lines of Code</h3>
+                <div class="value">${report.manifest.totalLines.toLocaleString()}</div>
+            </div>
+        </div>
+
+        ${report.recommendations.length > 0 ? `
+        <div class="recommendations">
+            <h2>Recommendations</h2>
+            <ul>
+                ${report.recommendations.map(r => `<li>${r}</li>`).join('')}
+            </ul>
+        </div>
+        ` : ''}
+
+        <h2>Findings by Severity</h2>
+        ${this.buildHTMLFindings(report)}
+    </div>
+</body>
+</html>`;
+  }
+
+  private buildHTMLFindings(report: AuditReport): string {
+    const bySeverity = this.groupBySeverity(report.findings);
+    let html = '';
+
+    for (const severity of [Severity.CRITICAL, Severity.HIGH, Severity.MEDIUM, Severity.LOW, Severity.INFO]) {
+      const findings = bySeverity[severity];
+      if (findings && findings.length > 0) {
+        html += `<h3 class="severity-${severity}">${severity.toUpperCase()} (${findings.length})</h3>`;
+        
+        for (const finding of findings) {
+          html += `
+            <div class="finding ${severity}">
+                <h4>${finding.title} ${finding.autoFixable ? '<span class="badge auto-fix">Auto-fixable</span>' : ''}</h4>
+                <p><strong>Category:</strong> ${finding.category}</p>
+                <p><strong>File:</strong> ${finding.file || 'N/A'}${finding.line ? `:${finding.line}` : ''}</p>
+                <p>${finding.description}</p>
+                ${finding.suggestion ? `<p><strong>Suggestion:</strong> ${finding.suggestion}</p>` : ''}
+            </div>
+          `;
+        }
+      }
+    }
+
+    return html;
+  }
+
+  private groupBySeverity(findings: any[]): Record<Severity, any[]> {
+    const grouped: Record<Severity, any[]> = {
+      [Severity.CRITICAL]: [],
+      [Severity.HIGH]: [],
+      [Severity.MEDIUM]: [],
+      [Severity.LOW]: [],
+      [Severity.INFO]: [],
+    };
+
+    for (const finding of findings) {
+      grouped[finding.severity].push(finding);
+    }
+
+    return grouped;
+  }
+
+  private getSeverityIcon(severity: Severity): string {
+    const icons = {
+      [Severity.CRITICAL]: '🔴',
+      [Severity.HIGH]: '🟠',
+      [Severity.MEDIUM]: '🟡',
+      [Severity.LOW]: '🟢',
+      [Severity.INFO]: '🔵',
+    };
+    return icons[severity] || '⚪';
+  }
+
+  private getSeverityWeight(severity: Severity): number {
+    const weights = {
+      [Severity.CRITICAL]: 5,
+      [Severity.HIGH]: 4,
+      [Severity.MEDIUM]: 3,
+      [Severity.LOW]: 2,
+      [Severity.INFO]: 1,
+    };
+    return weights[severity] || 0;
+  }
+
+  private getScoreColor(score: number): string {
+    if (score >= 90) return '#28a745';
+    if (score >= 70) return '#ffc107';
+    if (score >= 50) return '#fd7e14';
+    return '#dc3545';
+  }
+}
