+#!/usr/bin/env node
+
+import { Command } from 'commander';
+import dotenv from 'dotenv';
+import path from 'path';
+import { ConfigLoader } from './config/config-loader';
+import { AuditEngine } from './core/audit-engine';
+import { RepairEngine } from './core/repair-engine';
+import { ReportGenerator } from './reports/report-generator';
+import { logger, ConsoleReporter } from './utils/logger';
+import { BCBConfig } from './types';
+
+// Load environment variables
+dotenv.config();
+
+const program = new Command();
+
+program
+  .name('bcb')
+  .description('Better Call Bob - Autonomous CLI tool for auditing and repairing vibe-coded projects')
+  .version('1.0.0');
+
+// Audit command
+program
+  .command('audit')
+  .description('Audit a project for code quality, security, and best practices')
+  .argument('[path]', 'Project path to audit', '.')
+  .option('-c, --config <path>', 'Path to config file')
+  .option('-o, --output <path>', 'Output file path')
+  .option('-f, --format <format>', 'Output format (json, html, markdown, terminal)', 'terminal')
+  .option('-v, --verbose', 'Verbose output')
+  .action(async (projectPath: string, options: any) => {
+    try {
+      const resolvedPath = path.resolve(projectPath);
+      
+      ConsoleReporter.section('BCB - Better Call Bob');
+      ConsoleReporter.info(`Auditing project at: ${resolvedPath}`);
+
+      // Load configuration
+      const config = await ConfigLoader.load(resolvedPath);
+      if (options.verbose) {
+        config.output.verbose = true;
+      }
+
+      // Run audit
+      const auditEngine = new AuditEngine(config);
+      const report = await auditEngine.audit(resolvedPath, config);
+
+      // Generate report
+      const reportGenerator = new ReportGenerator();
+      await reportGenerator.generate(report, options.format, options.output);
+
+      // Exit with appropriate code
+      const criticalIssues = report.summary.bySeverity.critical || 0;
+      const highIssues = report.summary.bySeverity.high || 0;
+      
+      if (criticalIssues > 0) {
+        process.exit(2);
+      } else if (highIssues > 5) {
+        process.exit(1);
+      }
+      
+      process.exit(0);
+    } catch (error) {
+      ConsoleReporter.error(`Audit failed: ${error}`);
+      logger.error(`Audit error: ${error}`);
+      process.exit(1);
+    }
+  });
+
+// Repair command
+program
+  .command('repair')
+  .description('Repair issues found in the project')
+  .argument('[path]', 'Project path to repair', '.')
+  .option('-c, --config <path>', 'Path to config file')
+  .option('--auto', 'Automatically fix all auto-fixable issues without prompts')
+  .option('--ai', 'Enable AI-assisted repairs')
+  .option('--dry-run', 'Show what would be fixed without making changes')
+  .action(async (projectPath: string, options: any) => {
+    try {
+      const resolvedPath = path.resolve(projectPath);
+      
+      ConsoleReporter.section('BCB - Better Call Bob');
+      ConsoleReporter.info(`Repairing project at: ${resolvedPath}`);
+
+      // Load configuration
+      const config = await ConfigLoader.load(resolvedPath);
+      
+      // Override config with CLI options
+      if (options.auto) {
+        config.autoFix.enabled = true;
+        config.autoFix.requireApproval = false;
+      }
+      
+      if (options.ai && !config.ai.apiKey) {
+        ConsoleReporter.error('AI provider API key not configured. Set BCB_AI_API_KEY environment variable.');
+        process.exit(1);
+      }
+
+      // First, run audit to get findings
+      const auditEngine = new AuditEngine(config);
+      const report = await auditEngine.audit(resolvedPath, config);
+
+      if (report.findings.length === 0) {
+        ConsoleReporter.success('No issues found! Project is in good shape.');
+        process.exit(0);
+      }
+
+      if (options.dryRun) {
+        ConsoleReporter.info('Dry run mode - no changes will be made');
+        ConsoleReporter.info(`Would fix ${report.summary.autoFixableCount} auto-fixable issues`);
+        process.exit(0);
+      }
+
+      // Run repair
+      const repairEngine = new RepairEngine(config);
+      const results = await repairEngine.repair(report.findings, resolvedPath);
+
+      const successCount = results.filter(r => r.success).length;
+      ConsoleReporter.success(`Repair complete: ${successCount}/${results.length} fixes applied`);
+      
+      process.exit(0);
+    } catch (error) {
+      ConsoleReporter.error(`Repair failed: ${error}`);
+      logger.error(`Repair error: ${error}`);
+      process.exit(1);
+    }
+  });
+
+// Init command
+program
+  .command('init')
+  .description('Initialize BCB configuration in the current project')
+  .argument('[path]', 'Project path', '.')
+  .action(async (projectPath: string) => {
+    try {
+      const resolvedPath = path.resolve(projectPath);
+      
+      ConsoleReporter.section('BCB - Initialize Configuration');
+      
+      // Load default config
+      const { defaultConfig } = await import('./config/default-config');
+      
+      // Save to project
+      await ConfigLoader.save(resolvedPath, defaultConfig);
+      
+      ConsoleReporter.success('Configuration file created: .bcbrc.json');
+      ConsoleReporter.info('Edit the file to customize rules and settings');
+      
+      process.exit(0);
+    } catch (error) {
+      ConsoleReporter.error(`Initialization failed: ${error}`);
+      process.exit(1);
+    }
+  });
+
+// CI command
+program
+  .command('ci')
+  .description('Run audit in CI/CD mode with strict exit codes')
+  .argument('[path]', 'Project path to audit', '.')
+  .option('-c, --config <path>', 'Path to config file')
+  .option('--threshold <score>', 'Minimum score threshold (0-100)', '70')
+  .option('--max-critical <count>', 'Maximum allowed critical issues', '0')
+  .option('--max-high <count>', 'Maximum allowed high issues', '5')
+  .action(async (projectPath: string, options: any) => {
+    try {
+      const resolvedPath = path.resolve(projectPath);
+      const threshold = parseInt(options.threshold);
+      const maxCritical = parseInt(options.maxCritical);
+      const maxHigh = parseInt(options.maxHigh);
+
+      // Load configuration
+      const config = await ConfigLoader.load(resolvedPath);
+
+      // Run audit
+      const auditEngine = new AuditEngine(config);
+      const report = await auditEngine.audit(resolvedPath, config);
+
+      // Generate JSON report for CI
+      const reportGenerator = new ReportGenerator();
+      await reportGenerator.generate(report, 'json', 'bcb-report.json');
+
+      // Check thresholds
+      const criticalCount = report.summary.bySeverity.critical || 0;
+      const highCount = report.summary.bySeverity.high || 0;
+
+      console.log(`\nCI Results:`);
+      console.log(`  Score: ${report.score}/${threshold} (threshold)`);
+      console.log(`  Critical: ${criticalCount}/${maxCritical} (max)`);
+      console.log(`  High: ${highCount}/${maxHigh} (max)`);
+
+      if (criticalCount > maxCritical) {
+        ConsoleReporter.error(`Failed: ${criticalCount} critical issues (max: ${maxCritical})`);
+        process.exit(2);
+      }
+
+      if (highCount > maxHigh) {
+        ConsoleReporter.error(`Failed: ${highCount} high issues (max: ${maxHigh})`);
+        process.exit(2);
+      }
+
+      if (report.score < threshold) {
+        ConsoleReporter.error(`Failed: Score ${report.score} below threshold ${threshold}`);
+        process.exit(1);
+      }
+
+      ConsoleReporter.success('CI check passed!');
+      process.exit(0);
+    } catch (error) {
+      ConsoleReporter.error(`CI check failed: ${error}`);
+      process.exit(1);
+    }
+  });
+
+// Interactive command
+program
+  .command('interactive')
+  .description('Interactive mode for guided repairs')
+  .argument('[path]', 'Project path', '.')
+  .action(async (projectPath: string) => {
+    try {
+      const resolvedPath = path.resolve(projectPath);
+      
+      ConsoleReporter.section('BCB - Interactive Mode');
+      ConsoleReporter.info('This feature is coming soon!');
+      ConsoleReporter.info('For now, use: bcb audit && bcb repair');
+      
+      process.exit(0);
+    } catch (error) {
+      ConsoleReporter.error(`Interactive mode failed: ${error}`);
+      process.exit(1);
+    }
+  });
+
+// Parse arguments
+program.parse();
+
+// Made with Bob
